@if($categoryExpenses->sum('total')>0)const expenses=@json($categoryExpenses);new Chart(document.getElementById('expenseCategoryChart'),{type:'doughnut',data:{labels:expenses.map(x=>x.name),datasets:[{data:expenses.map(x=>x.total),backgroundColor:['#f4b400','#555b63','#e48b4c','#69a27d','#b9a46a','#d56e72','#7c8fb5']}]},options:{responsive:true,maintainAspectRatio:false,cutout:'64%',plugins:{legend:{position:'bottom',labels:{usePointStyle:true,boxWidth:7,font:{size:10}}}}}});@endif
@if($plans->sum('total')>0)const plans=@json($plans);new Chart(document.getElementById('mealPlanChart'),{type:'doughnut',data:{labels:plans.map(x=>x.package_type.replaceAll('_',' ')),datasets:[{data:plans.map(x=>x.total),backgroundColor:['#f4b400','#555b63','#69a27d']}]},options:{responsive:true,maintainAspectRatio:false,cutout:'66%',plugins:{legend:{position:'bottom',labels:{usePointStyle:true,boxWidth:7,font:{size:10}}}}}});@endif
document.getElementById('refreshDashboard').addEventListener('click',async function(){const page=document.querySelector('.content');page.classList.add('is-refreshing');this.disabled=true;try{const query=window.location.search;const response=await fetch('{{ route('dashboard.summary') }}'+query,{headers:{Accept:'application/json'}});const data=await response.json();Object.entries(data.cards).forEach(([key,value])=>{const el=document.querySelector('[data-kpi='+key+']');if(el)el.textContent=el.dataset.format==='money'?money(value):Number(value).toLocaleString()});Object.entries(data.deliveryStats).forEach(([meal,stats])=>Object.entries(stats).forEach(([key,value])=>{const el=document.querySelector('[data-delivery='+meal+'-'+key+']');if(el)el.textContent=value}));Object.entries(data.finance).forEach(([key,value])=>{const el=document.querySelector('[data-finance='+key+']');if(el&&typeof value==='number')el.textContent=money(key==='monthly_profit'?Math.abs(value):value)});Object.entries(data.alerts).forEach(([key,value])=>{const el=document.querySelector('[data-alert='+key+']');if(el)el.textContent=value});document.getElementById('dashboardUpdatedAt').textContent=data.refreshed_at}finally{page.classList.remove('is-refreshing');this.disabled=false}});
</script>@endpush
